sim = Sim(mesh; driver="LLG", name="${name}", integrator="DormandPrince", save_data=true)
sim.driver.alpha = ${alpha}
sim.driver.gamma = ${gamma}
sim.driver.integrator.tol = ${tol}

function init_fun(i, j, k, dx, dy, dz)
    x = i - ${center_x}
    y = j - ${center_y}
    r = sqrt(x^2 + y^2)
    if r < ${r0}
        return (0, 0, 1)
    end
    return (-y / r, x / r, 0)
end
init_m0(sim, init_fun)

function init_fun(x, y, z)
    r = sqrt(x^2 + y^2)
    if r < ${r0}e-9
        return (0, 0, 1)
    end
    return (sin(pi*x/${pitch}e-9), 0, cos(pi*x/${pitch}e-9))
end
init_m0(sim, init_fun)

function field_pulse(t)
    return exp(-t / ${tau})
end
add_zeeman(sim, (${Hx}, ${Hy}, ${Hz}), field_pulse)
